-- Cleanup
DROP TABLE IF EXISTS teachers;
DROP TABLE IF EXISTS faculty_schedules;

-- Create Tables
CREATE TABLE teachers (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    department TEXT,
    access_code TEXT UNIQUE NOT NULL
);

CREATE TABLE faculty_schedules (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    department TEXT,
    schedule TEXT DEFAULT '{}'
);

